// AUTO-GENERATED by workflow — art.
import { defineSprite, defineAnim, Painter } from '../../engine/sprites.js';
import { P, lighten, darken, mix, withAlpha } from '../../engine/palette.js';
import { defineIcon, panel, sym } from '../icons.js';
import { drawSlime, drawBat, drawWisp, drawBrute, drawHunter, registerHeroBody, drawHeroBody } from '../core.js';
import { registerDecals } from '../biome_decals.js';
import { DECOR_SETS, DECOR_CLUSTERS } from '../biome_decor.js';

// ============================ SWAMP 腐沼濕地 — ground decals + standing decor ============================
// Low-contrast ground decals (mud/algae/moss/roots/leaf-litter/gas-ring/cracked-mud) that read as
// texture variation on the swamp floor, never as pickups — no outline, no bright green/teal glow
// points, tones stay within ±10-18% of the biome's own floor colour family (#2c3a26 / #37472d).
// Standing decor: a half-sunken rotten stump, a muted earthy fungus cluster, a dead branch trailing
// hanging moss, and a moss/fungus-overgrown rotted marker post — all follow the existing bd_* finish
// (softShadow -> body -> rimLight -> outline(P.ink)).

// ---- shared low-key tones (from biomes.js BIOMES.swamp floor/floor2) ----
const swFloor  = '#2c3a26';
const swFloor2 = '#37472d';
const swGas    = darken(mix(P.slimeBog, P.sand, 0.35), 0.30); // muted khaki-olive marsh-gas glow (NOT bright toxic/teal)

// ============================ (a) GROUND DECALS ============================

defineSprite('decal_swamp_mudpatch', 12, 8, (p) => {          // irregular mud smear (h=8 so the ry=3 ellipse fits)
  p.ellipse(6, 4, 5, 3, darken(swFloor, 0.14));
  p.ellipse(5, 3, 3, 2, lighten(swFloor, 0.10));
  p.ellipse(8, 5, 2, 1.4, darken(swFloor, 0.08));
  p.speckle(2, 2, 8, 4, darken(swFloor, 0.22), 4, 101);
}, { anchor: 'center' });

defineSprite('decal_swamp_puddle', 13, 8, (p) => {            // shallow murky puddle, faint sheen (h=8 so the ry=3 ellipse fits)
  const water = mix(swFloor, P.murk, 0.4);
  p.ellipse(6, 4, 6, 3, darken(water, 0.06));
  p.ellipse(6, 4, 5, 2.2, water);
  p.dither(2, 3, 9, 2, water, lighten(water, 0.08));
  p.px(5, 3, withAlpha(P.bogL, 0.18));                        // subtle glow 1/2: faint wet sheen
  p.px(8, 4, withAlpha(P.bogL, 0.14));
}, { anchor: 'center' });

defineSprite('decal_swamp_algae', 11, 6, (p) => {             // dried algae stain
  p.ellipse(5, 3, 5, 2.4, mix(swFloor, swFloor2, 0.5));
  p.ellipse(4, 2, 3, 1.6, lighten(swFloor2, 0.12));
  p.speckle(1, 1, 9, 4, darken(swFloor, 0.16), 6, 47);
  p.speckle(2, 3, 7, 2, lighten(swFloor2, 0.10), 4, 19);
}, { anchor: 'center' });

defineSprite('decal_swamp_moss', 10, 6, (p) => {              // patchy ground moss
  p.ellipse(5, 3, 4, 2.2, lighten(swFloor2, 0.10));
  p.ellipse(4, 2, 2.4, 1.4, lighten(swFloor2, 0.16));
  p.speckle(1, 1, 8, 4, darken(swFloor2, 0.12), 5, 61);
}, { anchor: 'center' });

defineSprite('decal_swamp_roots', 14, 5, (p) => {             // gnarled surface root tangle
  const root = mix(P.barkD, swFloor, 0.55);
  p.line(1, 4, 6, 1, root);
  p.line(6, 1, 12, 3, darken(root, 0.10));
  p.line(3, 4, 9, 4, lighten(root, 0.08));
  p.speckle(1, 1, 12, 3, darken(swFloor, 0.14), 4, 29);
}, { anchor: 'center' });

defineSprite('decal_swamp_leaflitter', 12, 8, (p) => {        // decayed leaf litter
  p.ellipse(6, 5, 5, 2.6, darken(swFloor, 0.10));
  p.px(3, 4, lighten(swFloor2, 0.14)); p.px(7, 3, lighten(swFloor2, 0.12));
  p.px(9, 5, darken(swFloor, 0.16)); p.px(5, 6, lighten(swFloor2, 0.10)); p.px(8, 6, darken(swFloor, 0.12));
  p.speckle(2, 2, 8, 4, mix(swFloor, P.bark, 0.15), 3, 71);
}, { anchor: 'center' });

defineSprite('decal_swamp_gasring', 10, 8, (p) => {           // marsh-gas bubble ring imprint (h=8 so the r=3 ring fits)
  p.ellipse(5, 4, 4, 1.8, darken(swFloor, 0.08));
  p.ring(5, 4, 3, withAlpha(swGas, 0.16));                    // subtle glow 2/2: faint gas ring
  p.ring(5, 4, 1.6, withAlpha(swGas, 0.14));
}, { anchor: 'center' });

defineSprite('decal_swamp_bogcrack', 11, 6, (p) => {          // sun-cracked dried mud (h=6 so the ry=2 ellipse fits)
  p.ellipse(5, 3, 5, 2, darken(swFloor, 0.06));
  p.line(1, 4, 5, 1, lighten(swFloor, 0.14));
  p.line(5, 1, 9, 3, lighten(swFloor, 0.12));
  p.line(3, 3, 6, 4, lighten(swFloor, 0.10));
}, { anchor: 'center' });

// ============================ (b) STANDING DECOR ============================

defineSprite('bdx_swamp_sunkenstump', 16, 16, (p) => {        // half-sunken rotten stump
  p.softShadow(8, 14, 6, 2, 0.4);
  p.ellipse(8, 13, 7, 2.6, mix(swFloor, P.murk, 0.4));        // murky water ring at base
  p.ellipse(8, 13, 5, 1.8, mix(swFloor, P.murk, 0.25));
  p.rect(5, 5, 6, 8, mix(P.barkD, P.murk, 0.3));
  p.rect(5, 5, 2, 8, mix(P.bark, P.bog, 0.25));
  p.ellipse(8, 5, 3.4, 1.8, mix(P.barkD, P.murk, 0.2));
  p.line(5, 12, 1, 14, mix(P.barkD, P.murk, 0.3));            // exposed roots splaying into mud
  p.line(11, 12, 14, 15, mix(P.barkD, P.murk, 0.3));
  p.line(6, 13, 4, 15, darken(P.barkD, 0.1));
  p.px(6, 6, P.bogL); p.px(10, 7, darken(P.bogL, 0.1)); p.px(9, 9, P.moss);   // moss/fungus patches
  p.speckle(5, 6, 6, 6, darken(P.barkD, 0.2), 5, 37);
  p.rimLight(P.rimCool, 0.28);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineAnim('bdx_swamp_fungusCluster', 14, 12, 2, (p, f) => {  // muted earthy fungus cluster (breathing)
  p.softShadow(7, 11, 5, 1.6, 0.38);
  // NOTE engine Painter.vline is (y0, y1, x, col) — stems sit under the caps at x=4/9/7
  p.vline(8, 11, 4, P.bone); p.vline(7, 11, 9, mix(P.bone, P.bog, 0.2)); p.vline(9, 11, 7, P.bone);
  const glowAmt = f === 1 ? 0.22 : 0.15;                      // 極微弱 marsh-gas shimmer (the pack's single glow)
  p.ellipse(4, 7, 2.4, 1.6, mix(P.bog, P.bone, 0.45));
  p.ellipse(9, 6, 3, 2, mix(P.bogL, P.bone, 0.4));
  p.ellipse(7, 8, 1.8, 1.2, mix(P.bog, P.bone, 0.5));
  p.glow(9, 6, 1.8, P.slimeBog, glowAmt, 2);
  p.px(9, 5, lighten(mix(P.bogL, P.bone, 0.4), 0.15));
  p.px(4, 6, lighten(mix(P.bog, P.bone, 0.45), 0.12));
  p.speckle(3, 5, 8, 5, darken(P.bog, 0.2), 3, 53);
  p.rimLight(P.rim, 0.25);
  p.outline(P.ink);
}, { anchor: 'feet', fps: 2 });

defineSprite('bdx_swamp_hangingmoss', 12, 22, (p) => {        // dead branch trailing hanging moss
  p.softShadow(6, 21, 4, 1.4, 0.3);
  p.line(6, 0, 6, 6, P.barkD); p.line(6, 0, 10, 6, P.barkD);  // right twig reaches x=10 so that strand hangs FROM it
  p.line(6, 1, 3, 6, darken(P.barkD, 0.08));                  // left twig anchors the x=3/4 strands
  p.px(6, 0, lighten(P.barkD, 0.15));
  for (let i = 0; i < 5; i++) {
    const x = 3 + i * 1.8 | 0;
    const len = 10 + (i % 3) * 3;
    p.vline(6, 6 + len - 1, x, mix(P.bog, P.moss, 0.35));    // vline(y0,y1,x) — strand hangs from the branch
    p.px(x, 6 + len - 1, P.bogL);
  }
  p.speckle(2, 6, 8, 6, darken(P.bog, 0.15), 4, 43);
  p.rimLight(P.rimCool, 0.25);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineSprite('bdx_swamp_bogpost', 13, 18, (p) => {            // rotted marker post overgrown w/ fungus
  p.softShadow(6, 17, 5, 1.6, 0.38);
  p.rect(5, 3, 3, 14, mix(P.barkD, P.murk, 0.25));
  p.rect(5, 3, 1, 14, mix(P.bark, P.bog, 0.2));
  p.px(7, 3, darken(P.barkD, 0.2));
  p.line(2, 6, 8, 5, mix(P.barkD, P.murk, 0.2));              // broken signpost arm
  p.vline(10, 15, 6, P.moss); p.px(6, 9, P.bogL); p.px(6, 6, P.bogL);   // vline(y0,y1,x): moss creeps up the post's lower half
  p.ellipse(5, 8, 1.4, 1, mix(P.bog, P.bone, 0.4));
  p.speckle(4, 4, 5, 12, darken(P.barkD, 0.18), 4, 67);
  p.rimLight(P.rim, 0.28);
  p.outline(P.ink);
}, { anchor: 'feet' });

// ============================ (c) registration ============================
registerDecals('swamp', [
  'decal_swamp_mudpatch', 'decal_swamp_puddle', 'decal_swamp_algae', 'decal_swamp_moss',
  'decal_swamp_roots', 'decal_swamp_leaflitter', 'decal_swamp_gasring', 'decal_swamp_bogcrack',
]);
(DECOR_SETS['swamp'] = DECOR_SETS['swamp'] || []).push(
  'bdx_swamp_sunkenstump', 'bdx_swamp_fungusCluster', 'bdx_swamp_hangingmoss', 'bdx_swamp_bogpost'
);
(DECOR_CLUSTERS['swamp'] = DECOR_CLUSTERS['swamp'] || []).push(
  'bdx_swamp_fungusCluster', 'bdx_swamp_sunkenstump'
);

